class Solution:
    def kMirror(self, k, n):
        def is_pal_str(s):
            return s == s[::-1]

        candidates = []
        length = 1
        while len(candidates) < n:
            half_len = (length + 1) // 2
            lo = k ** (half_len - 1) if half_len > 1 else 1
            hi = k ** half_len
            for half_val in range(lo, hi):
                hd = []
                tmp = half_val
                for _ in range(half_len):
                    hd.append(tmp % k)
                    tmp //= k
                hd.reverse()
                if length % 2 == 0:
                    full_digits = hd + hd[::-1]
                else:
                    full_digits = hd + hd[-2::-1]
                dec = 0
                for d in full_digits:
                    dec = dec * k + d
                if is_pal_str(str(dec)):
                    candidates.append(dec)
            length += 1
        candidates.sort()
        return sum(candidates[:n])

