class Solution:
    def kMirror(self, k, n):
        def to_base_k(x, base):
            digits = []
            while x > 0:
                digits.append(x % base)
                x //= base
            digits.reverse()
            return digits

        def is_pal_list(lst):
            return lst == lst[::-1]

        count = 0
        total = 0
        length = 1
        while count < n:
            half_len = (length + 1) // 2
            start = 10 ** (half_len - 1) if half_len > 1 else 1
            end = 10 ** half_len
            for half in range(start, end):
                s = str(half)
                if length % 2 == 0:
                    full = s + s[::-1]
                else:
                    full = s + s[-2::-1]
                num = int(full)
                digits = to_base_k(num, k)
                if is_pal_list(digits):
                    count += 1
                    total += num
                    if count == n:
                        return total
            length += 1
        return total

