var kMirror = function(k, n) {
    function toBaseK(x, base) {
        const digits = [];
        while (x > 0) {
            digits.push(x % base);
            x = Math.floor(x / base);
        }
        digits.reverse();
        return digits;
    }
    function isPalArr(arr) {
        for (let i = 0, j = arr.length - 1; i < j; i++, j--) {
            if (arr[i] !== arr[j]) return false;
        }
        return true;
    }
    let count = 0;
    let total = 0;
    let length = 1;
    while (count < n) {
        const halfLen = Math.floor((length + 1) / 2);
        const start = halfLen > 1 ? Math.pow(10, halfLen - 1) : 1;
        const end = Math.pow(10, halfLen);
        for (let half = start; half < end; half++) {
            const s = String(half);
            let full;
            if (length % 2 === 0) {
                full = s + s.split('').reverse().join('');
            } else {
                full = s + s.slice(0, -1).split('').reverse().join('');
            }
            const num = parseInt(full, 10);
            const digits = toBaseK(num, k);
            if (isPalArr(digits)) {
                count++;
                total += num;
                if (count === n) return total;
            }
        }
        length++;
    }
    return total;
};
